CREATE TABLE pipeline_messages(message_id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, run_id TEXT NOT NULL REFERENCES runs(id) ON DELETE CASCADE, branch_id TEXT REFERENCES branches(id), pipeline_id TEXT NOT NULL REFERENCES pipelines(id) ON DELETE CASCADE, pipeline_version INTEGER NOT NULL, pipeline_node_id TEXT NOT NULL, direction TEXT NOT NULL, port TEXT NOT NULL, schema_id TEXT NOT NULL, data_json TEXT NOT NULL, artifact_ids_json TEXT NOT NULL, provenance_json TEXT NOT NULL, status TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE INDEX idx_pipeline_messages_run_node ON pipeline_messages(run_id,pipeline_node_id,direction,port);
CREATE TABLE ollama_settings(user_id TEXT PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, base_url TEXT NOT NULL, default_model TEXT, companion_url TEXT, updated_at TEXT NOT NULL);
